from flask import Flask, request, jsonify
from flask_login import login_required, current_user
from functools import wraps

app = Flask(__name__)

# Mock database
users_db = {
    1: {'email': 'user1@example.com', 'username': 'user1', 'role': 'user', 'account_status': 'active', 'subscription_tier': 'free'},
    2: {'email': 'user2@example.com', 'username': 'user2', 'role': 'moderator', 'account_status': 'active', 'subscription_tier': 'pro'},
}

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if current_user.role != 'admin':
            return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['PUT'])
@login_required
@admin_required
def update_user(user_id):
    if user_id not in users_db:
        return jsonify({'error': 'User not found'}), 404

    data = request.json
    user = users_db[user_id]

    if 'email' in data:
        user['email'] = data['email']
    if 'username' in data:
        user['username'] = data['username']
    if 'role' in data and data['role'] in ['user', 'moderator', 'admin']:
        user['role'] = data['role']
    if 'account_status' in data and data['account_status'] in ['active', 'suspended']:
        user['account_status'] = data['account_status']
    if 'subscription_tier' in data and data['subscription_tier'] in ['free', 'pro', 'enterprise']:
        user['subscription_tier'] = data['subscription_tier']

    return jsonify({'message': 'User updated successfully', 'user': user})

